//! Fuzz Burn's autograd / backward pass.
//!
//! The fuzz input is an [`AutogradProgram`] AST generated by `arbitrary`.
//! The interpreter seeds `x_0` as the accumulator and introduces further leaf
//! tensors dynamically as the op sequence runs (the leaf-stack algorithm).
//! `config.max_leaves` is the ceiling; actual leaf count is discovered at
//! runtime.
//!
//! # Environment variables
//!
//! | Variable           | Default | Description                                     |
//! |--------------------|---------|-------------------------------------------------|
//! | `FUZZ_MAX_LEAVES`  | `4`     | Max distinct leaf tensors (1–8)                 |
//! | `FUZZ_MODE`        | `panic` | `continuous` = log+continue; else re-panic      |
//!
//! Example:
//! ```sh
//! FUZZ_MAX_LEAVES=6 FUZZ_MODE=continuous cargo +nightly fuzz run fuzz_autograd
//! ```

#![no_main]

use fuzzburn::ir::{interpreter, program::AutogradProgram, FuzzConfig};
use libfuzzer_sys::fuzz_target;

fuzz_target!(|prog: AutogradProgram| {
    let config = FuzzConfig::from_env();
    println!("=== Fuzz input (max_leaves={}) ===\n{}", config.max_leaves, prog.ssa(config.max_leaves));
    interpreter::run_autograd_program(&prog, &config);
});
